# Extrude all 6 hole profiles as cuts into Enclosure_Shell
import math

enclosure = rootComp.bRepBodies.itemByName("Enclosure_Shell")
sketch = rootComp.sketches.itemByName("Enclosure_Screw_Holes")

if not enclosure:
    result = {"error": "Enclosure_Shell not found"}
elif not sketch:
    result = {"error": "Enclosure_Screw_Holes sketch not found"}
elif sketch.profiles.count != 6:
    result = {"error": f"Expected 6 profiles, found {sketch.profiles.count}"}
else:
    extrudes = rootComp.features.extrudeFeatures
    hole_depth = 1.0  # cm - cut 10mm deep into enclosure

    # Collect all 6 profiles into an ObjectCollection for a single cut operation
    profiles_coll = adsk.core.ObjectCollection.create()
    for i in range(sketch.profiles.count):
        profiles_coll.add(sketch.profiles.item(i))

    ext_input = extrudes.createInput(
        profiles_coll,
        adsk.fusion.FeatureOperations.CutFeatureOperation
    )
    # Cut downward (negative Z direction) into the enclosure
    ext_input.setDistanceExtent(
        False,
        adsk.core.ValueInput.createByReal(hole_depth)
    )
    ext_input.participantBodies = [enclosure]

    vol_before = enclosure.volume
    ext = extrudes.add(ext_input)
    vol_after = enclosure.volume

    result = {
        "status": "success",
        "holes_cut": 6,
        "hole_radius_cm": 0.15,
        "hole_diameter_mm": 3.0,
        "hole_depth_cm": hole_depth,
        "volume_before_cm3": round(vol_before, 4),
        "volume_after_cm3": round(vol_after, 4),
        "volume_removed_cm3": round(vol_before - vol_after, 4)
    }

# Cut 6 holes downward from the offset plane into Enclosure_Shell
import math

enclosure = rootComp.bRepBodies.itemByName("Enclosure_Shell")
sketch = rootComp.sketches.itemByName("Enclosure_Screw_Holes")

if not enclosure:
    result = {"error": "Enclosure_Shell not found"}
elif not sketch:
    result = {"error": "Sketch not found"}
elif sketch.profiles.count != 6:
    result = {"error": f"Expected 6 profiles, got {sketch.profiles.count}"}
else:
    extrudes = rootComp.features.extrudeFeatures

    profiles_coll = adsk.core.ObjectCollection.create()
    for i in range(sketch.profiles.count):
        profiles_coll.add(sketch.profiles.item(i))

    ext_input = extrudes.createInput(
        profiles_coll,
        adsk.fusion.FeatureOperations.CutFeatureOperation
    )

    # Cut DOWNWARD: distance = 1.01 cm (to go through the 0.01 cm gap + 1.0 cm into enclosure)
    ext_input.setDistanceExtent(
        False,
        adsk.core.ValueInput.createByReal(1.01)
    )
    # Negative direction = downward (-Z)
    ext_input.setOneSideExtent(
        adsk.fusion.DistanceExtentDefinition.create(
            adsk.core.ValueInput.createByReal(1.01)
        ),
        adsk.fusion.ExtentDirections.NegativeExtentDirection
    )
    ext_input.participantBodies = [enclosure]

    vol_before = enclosure.volume
    ext = extrudes.add(ext_input)
    vol_after = enclosure.volume

    result = {
        "status": "success" if (vol_before - vol_after) > 0 else "FAILED - no volume change",
        "volume_before": round(vol_before, 4),
        "volume_after": round(vol_after, 4),
        "volume_removed": round(vol_before - vol_after, 4)
    }
